declare type SkillData = {
    skill:string;
    domain:string;
    intent:string;
};

export interface OTARecord {
    id:string;
    subsystem:string;
    changes:string;
    length:number;
    toVersion:string;
    dependencies:any;
    downloaded:boolean;
}

export default class SchedulerService {
    // {jibo.scheduler#init}
    init(service:any, done:Function): void;
    // {jibo.scheduler#otaDownloadAndInstall}
    otaDownloadAndInstall(callback:(err?:Error) => void):void;
    // {jibo.scheduler#otaDownloadStatus
    otaDownloadStatus(callback:(err:Error, response?:any) => void):void;
    // {jibo.scheduler#otaCheckUpdates
    otaCheckUpdates(callback:(err:Error, response?:Array<OTARecord>) => void):void;
    // {jibo.scheduler#addJob}
    addJob(schedule:string, data:SkillData, callback:(err:Error, jobId?:string) => void):void;
    // {jibo.scheduler#removeJob}
    removeJob(jobId:string, callback:(err?:Error) => void):void;
    // {jibo.scheduler#listJobs}
    listJobs(callback:(err:Error, list?:any) => void):void;
    // {jibo.scheduler#hasJob}
    hasJob(jobId:string, callback:(err:Error, data?:any) => void):void;
    // {jibo.scheduler#backupRobot}
    backupRobot(callback:(err?:Error) => void):void;
    // {jibo.scheduler#backupStatus}
    backupStatus(callback:(err:Error, response?:any) => void):void;
}
